-- DDL, DML, defaults, RETURNING, ALTER.
CREATE TABLE d2 (id int NOT NULL, name text DEFAULT 'anon', score float8 DEFAULT 1.5, ok bool);
INSERT INTO d2 (id) VALUES (1);
INSERT INTO d2 VALUES (2, 'bolt', DEFAULT, true), (3, 'nut', 7.25, false) RETURNING id, name, score;
SELECT * FROM d2 ORDER BY id;
UPDATE d2 SET score = score * 2 WHERE ok RETURNING id, score;
DELETE FROM d2 WHERE id = 1 RETURNING name;
SELECT count(*) FROM d2;
ALTER TABLE d2 ADD COLUMN tag text DEFAULT 'zz';
SELECT id, tag FROM d2 ORDER BY id;
ALTER TABLE d2 RENAME COLUMN tag TO label;
ALTER TABLE d2 DROP COLUMN ok;
ALTER TABLE d2 RENAME TO d2renamed;
SELECT id, name, score, label FROM d2renamed ORDER BY id;
DROP TABLE d2renamed;
PREPARE dq (int) AS SELECT $1 + 1;
EXECUTE dq(41);
DEALLOCATE dq;

-- PRIMARY KEY / UNIQUE enforcement.
CREATE TABLE pk2 (id int PRIMARY KEY, email text UNIQUE, note text);
INSERT INTO pk2 VALUES (1, 'a@x', 'first');
INSERT INTO pk2 VALUES (1, 'b@x', 'dup pk');
INSERT INTO pk2 VALUES (2, 'a@x', 'dup email');
INSERT INTO pk2 VALUES (2, NULL, 'null unique ok');
INSERT INTO pk2 VALUES (3, NULL, 'nulls never collide');
UPDATE pk2 SET id = 2 WHERE id = 1;
INSERT INTO pk2 (id) VALUES (NULL);
SELECT id, email FROM pk2 ORDER BY id;
DROP TABLE pk2;
-- foreign key referential actions: CASCADE / SET NULL / SET DEFAULT
DROP TABLE IF EXISTS gc; DROP TABLE IF EXISTS ch; DROP TABLE IF EXISTS pa;
CREATE TABLE pa (id int PRIMARY KEY, v text);
CREATE TABLE ch (id int PRIMARY KEY, pid int REFERENCES pa(id) ON DELETE CASCADE ON UPDATE CASCADE, w text);
CREATE TABLE gc (id int PRIMARY KEY, cid int REFERENCES ch(id) ON DELETE CASCADE, z text);
INSERT INTO pa VALUES (1,'a'),(2,'b'),(3,'c');
INSERT INTO ch VALUES (10,1,'c1'),(11,1,'c2'),(12,2,'c3');
INSERT INTO gc VALUES (100,10,'g1'),(101,12,'g2');
DELETE FROM pa WHERE id = 1;
SELECT * FROM ch ORDER BY id;
SELECT * FROM gc ORDER BY id;
UPDATE pa SET id = 20 WHERE id = 2;
SELECT * FROM ch ORDER BY id;
SELECT * FROM pa ORDER BY id;
DROP TABLE gc; DROP TABLE ch; DROP TABLE pa;
CREATE TABLE pa (id int PRIMARY KEY);
CREATE TABLE ch (id int PRIMARY KEY, pid int DEFAULT 99 REFERENCES pa(id) ON DELETE SET NULL ON UPDATE SET DEFAULT);
INSERT INTO pa VALUES (1),(2),(99);
INSERT INTO ch VALUES (10,1),(11,2);
DELETE FROM pa WHERE id = 1;
SELECT * FROM ch ORDER BY id;
UPDATE pa SET id = 5 WHERE id = 2;
SELECT * FROM ch ORDER BY id;
DELETE FROM pa WHERE id = 99;
SELECT * FROM ch ORDER BY id;
DROP TABLE ch; DROP TABLE pa;
-- SET NULL against NOT NULL child column
CREATE TABLE pa (id int PRIMARY KEY);
CREATE TABLE ch (id int PRIMARY KEY, pid int NOT NULL REFERENCES pa(id) ON DELETE SET NULL);
INSERT INTO pa VALUES (1);
INSERT INTO ch VALUES (10,1);
DELETE FROM pa WHERE id = 1;
SELECT * FROM ch;
DROP TABLE ch; DROP TABLE pa;
-- SET DEFAULT with a default that does not exist in parent
CREATE TABLE pa (id int PRIMARY KEY);
CREATE TABLE ch (id int PRIMARY KEY, pid int DEFAULT 77 REFERENCES pa(id) ON DELETE SET DEFAULT);
INSERT INTO pa VALUES (1);
INSERT INTO ch VALUES (10,1);
DELETE FROM pa WHERE id = 1;
SELECT * FROM ch;
DROP TABLE ch; DROP TABLE pa;
-- restrict still blocks
CREATE TABLE pa (id int PRIMARY KEY);
CREATE TABLE ch (id int, pid int REFERENCES pa(id) ON DELETE RESTRICT);
INSERT INTO pa VALUES (1);
INSERT INTO ch VALUES (10,1);
DELETE FROM pa WHERE id = 1;
DROP TABLE ch; DROP TABLE pa;
-- self-referential cascade
CREATE TABLE tree (id int PRIMARY KEY, parent int REFERENCES tree(id) ON DELETE CASCADE);
INSERT INTO tree VALUES (1,NULL),(2,1),(3,2),(4,NULL);
DELETE FROM tree WHERE id = 1;
SELECT * FROM tree ORDER BY id;
DROP TABLE tree;
-- rollback restores cascaded children
CREATE TABLE pa (id int PRIMARY KEY);
CREATE TABLE ch (id int PRIMARY KEY, pid int REFERENCES pa(id) ON DELETE CASCADE);
INSERT INTO pa VALUES (1);
INSERT INTO ch VALUES (10,1);
BEGIN;
DELETE FROM pa WHERE id = 1;
SELECT count(*) FROM ch;
ROLLBACK;
SELECT * FROM ch;
DROP TABLE ch; DROP TABLE pa;
